module interrupt_controller(  
    input wire clk,  
    input wire rst,  
    input wire int_req,  
    input wire enable,  
    output reg int_active  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            int_active <= 0;  
        else if (enable)  
            int_active <= int_active | int_req;  
        else  
            int_active <= 0;  
    end  
endmodule
